-- =============================================================================
-- Kinara Store Hub — Full Database Setup
-- =============================================================================
--
-- STEP 1 — Run this block once as root/admin to create the DB, user, and perms.
--          Edit the password before running in production.
--
--   mysql -u root -p < database/kinarahub.sql
--
-- -----------------------------------------------------------------------------
-- 1a. Create database
-- -----------------------------------------------------------------------------
CREATE DATABASE IF NOT EXISTS `kinarahub`
    CHARACTER SET utf8mb4
    COLLATE utf8mb4_unicode_ci;

-- -----------------------------------------------------------------------------
-- 1b. Create application user
--     Replace 'StrongPass@123' with a secure password in production.
-- -----------------------------------------------------------------------------
CREATE USER IF NOT EXISTS 'kinarahub_app'@'localhost'
    IDENTIFIED BY 'StrongPass@123';

-- For remote/production hosts replace 'localhost' with the app-server IP:
-- CREATE USER IF NOT EXISTS 'kinarahub_app'@'<APP_SERVER_IP>'
--     IDENTIFIED BY 'StrongPass@123';

-- -----------------------------------------------------------------------------
-- 1c. Grant minimum required privileges
-- -----------------------------------------------------------------------------
GRANT SELECT, INSERT, UPDATE, DELETE, CREATE, ALTER, INDEX, DROP, REFERENCES
    ON `kinarahub`.*
    TO 'kinarahub_app'@'localhost';

FLUSH PRIVILEGES;

-- -----------------------------------------------------------------------------
-- 1d. Select the database for the rest of this script
-- -----------------------------------------------------------------------------
USE `kinarahub`;

